DELETE FROM `creature_addon`  WHERE `guid` BETWEEN 13000000 AND 13499999;
DELETE FROM `gameobject`      WHERE `guid` BETWEEN 13500000 AND 13999999;
DELETE FROM `pool_creature`   WHERE `pool_entry` BETWEEN 131000000 AND 131999999;
DELETE FROM `pool_gameobject` WHERE `pool_entry` BETWEEN 131000000 AND 131999999;
DELETE FROM `pool_template`   WHERE `entry` BETWEEN 131000000 AND 131999999;
DELETE FROM `waypoint_data`   WHERE `id` BETWEEN 131000000 AND 131999999;







-- Orphan cleanup: drop nelt-only spawns whose +3600000 clone template we haven't imported yet
-- (the 119 Molten Front/Firelands NPCs — handled by the template-import phase), + dangling addon/pool.
DELETE c FROM `creature` c LEFT JOIN `creature_template` ct ON ct.`entry`=c.`id` WHERE c.`map`=751 AND c.`guid`>=13000000 AND ct.`entry` IS NULL;
DELETE g FROM `gameobject` g LEFT JOIN `gameobject_template` gt ON gt.`entry`=g.`id` WHERE g.`map`=751 AND g.`guid`>=13500000 AND gt.`entry` IS NULL;
DELETE a FROM `creature_addon` a LEFT JOIN `creature` c ON c.`guid`=a.`guid` WHERE a.`guid`>=13000000 AND c.`guid` IS NULL;
DELETE p FROM `pool_creature` p LEFT JOIN `creature` c ON c.`guid`=p.`guid` WHERE p.`pool_entry`>=131000000 AND c.`guid` IS NULL;
DELETE p FROM `pool_gameobject` p LEFT JOIN `gameobject` g ON g.`guid`=p.`guid` WHERE p.`pool_entry`>=131000000 AND g.`guid` IS NULL;
